//*****************************************************************************
//
// File Name        : setValueToOutput.js
// Title            : SET Grid Setpoint with Output Switching
// Author           : http://www.prochazka.zde.cz
// Created          : 30-04-2025, 21:20
// Revised          : 30-04-2025, 22:30
// Version          : 1.10
// Target Platform  : Node-RED
//
//*****************************************************************************

// Debugging flag
const debug = false;  // Nastavte na true pro zapnutí debug zpráv

//definice globalních funkci
const fGetConfigProperty = global.get('getConfigProperty');
const nConvertUnsignetToSignet = global.get('nConvertUnsignetToSignet'); // nConvertSignetUnsignetINT16

// Kontrola, zda funkce existuje
if (typeof nConvertUnsignetToSignet !== 'function') {
    node.error("Globální funkce nebyly nalezeny. <-FORM Battery Control -- convert Unsignet to signet");
    return null;
}


// Získat poslední odeslanou hodnotu z kontextu
let nLastValue_Set_Grid_Point = context.get('nLastValue_Set_Grid_Point');
let lastOutputTarget = context.get('lastOutputTarget');
const outputTarget = !!fGetConfigProperty("nControl_Mode_ESS_AC_Grid"); //dotaz na data z globalni strukturu - true = první výstup, false = druhý výstup

// Načtení hodnot z msg.payload
const int32 = parseFloat(msg.payload.nSet_Grid_Point) || 0;
const nGET_Grid_Feed_2706 = -Math.abs(parseFloat(msg.payload.nGET_Grid_Feed_2706)) || 0; // Převod na záporné číslo registr 2706

// Použití konverzní funkce pro debug a druhý výstup
//const convert_writegridpoint = nConvertUnsignetToSignet(int32);
const convert_nGET_Grid_Feed_2706 = nConvertUnsignetToSignet(nGET_Grid_Feed_2706);

// Příprava zpráv pro Modbus uzly
let modbusMsg1 = null;  // Pro první výstup (INT32 jako 2xINT16)
let modbusMsg2 = null;  // Pro druhý výstup (INT16)

// Porovnání a nastavení omezení výkonu
let finalValue;
if (int32 < nGET_Grid_Feed_2706) {
    if (debug) {
        node.warn(`Omezení výstupního výkonu na: ${nGET_Grid_Feed_2706}`);
    }
    finalValue = nGET_Grid_Feed_2706; // Poslat omezený výkon
} else {
    if (debug) {
        node.warn(`Bez omezení výstupního výkonu: ${int32}`);
    }
    finalValue = int32; // Poslat původní hodnotu
}

// Kontrola, zda se hodnota změnila oproti poslední odeslané nebo se změnil cíl výstupu
let shouldSend = true;
if (nLastValue_Set_Grid_Point === finalValue && lastOutputTarget === outputTarget) {
    shouldSend = false;
    if (debug) {
        node.warn(`Hodnota se nezměnila (${finalValue}) a cíl výstupu je stále stejný, neposílám.`);
    }
} else if (lastOutputTarget !== outputTarget) {
    if (debug) {
        node.warn(`Změnil se cíl výstupu z ${lastOutputTarget} na ${outputTarget}, odesílám hodnotu.`);
    }
}

// Uložení poslední hodnoty a cíle výstupu do kontextu
context.set('nLastValue_Set_Grid_Point', finalValue);
context.set('lastOutputTarget', outputTarget);


// Zpráva pro debug uzel
let targetRegister = outputTarget ? "2716_int32" : "2700_int16";

let debugMsg = {
    payload: {
        "finalValue": finalValue,
        "convert_nGET_Grid_Feed_2706": convert_nGET_Grid_Feed_2706,
        "int32": int32,
        "nGET_Grid_Feed_2706": nGET_Grid_Feed_2706,
        "outputTarget": outputTarget,
        "targetRegister": targetRegister
    }
};

// Pokud se hodnota změnila nebo ještě žádná nebyla odeslána
if (shouldSend) {
    if (outputTarget) {
        // První výstup - pro INT32 rozdělený na 2x INT16
        // Konverze na beznaménkové 32-bitové číslo pomocí bitového posunu nulou
        let unsignedInt32 = finalValue >>> 0;

        // Extrakce horních 16 bitů (vyšší slovo) pomocí bitového posunu vpravo a maskování
        let high = (unsignedInt32 >> 16) & 0xFFFF;

        // Extrakce spodních 16 bitů (nižší slovo) pomocí maskování
        let low = unsignedInt32 & 0xFFFF;

        // Vytvoření pole hodnot pro FC16
        modbusMsg1 = { payload: [high, low] };

        if (debug) {
            node.warn(`Odesílám INT32 jako 2xINT16: [${high}, ${low}]`);
        }
    } else {
        // Druhý výstup - pouze INT16 (signet)
        modbusMsg2 = { payload: nConvertUnsignetToSignet(finalValue) };

        if (debug) {
            node.warn(`Odesílám INT16: ${nConvertUnsignetToSignet(finalValue)}`);
        }
    }
}

// Vrácení výsledků na správné výstupy
return [modbusMsg1, modbusMsg2, debugMsg];

// predpokladáme big-endian poradie
let unsignedValue = msg.payload[1]

// Prevod na signed 16-bit integer
let signedValue = unsignedValue > 0x7FFF ? unsignedValue - 0x10000 : unsignedValue;

// Připravit hodnotu pro zobrazení
msg.payload = {
    value: signedValue,
    isActive: global.get("nControl_Mode_ESS_AC_Grid")  // Aktivní když je přepínač OFF
};

return msg;

//*****************************************************************************
//
// File Name        : N/A
// Title            : AC LOAD
// Author           : http://www.prochazka.zde.cz
// Created          : 20-06-2024, 11:00
// Revised          : 28-06-2025, 14:23
// Version          : 1.40
// Target Platform  : Node-RED
//
// This code is distributed under the GNU Public License
// Všechny informace jsou zahrnuty pod GPL licenci, pokud není explicitně uveden jiný typ licence.
// Používání těchto stránek a produktů ke komerčním účelům lze jen se souhlasem autora.
// Všechna práva vyhrazena (c) 1997 - 2025 hacesoft.
//
//*****************************************************************************
// com.victronenergy.system má ID 100 (Cerbo)
// com.victronenergy.battery má ID 100(Lynx Shunt)
// com.victronenergy.vebus má ID 227(MP - II)
// com.victronenergy.solarcharger má v případě prvního MPPT ID 100, další potom ID 1 a 2(já mám tři MPPT)
// com.victronenergy.grid má 31(elektroměr EM540 přes USB)

// Debugging flag
const debug = false;  // Nastavte na true pro zapnutí debug zpráv

// Definice konstanty pro očekávaný počet prvků
const EXPECTED_ARRAY_LENGTH = 24;

//definice globalních funkci
const fGetConfigProperty = global.get('getConfigProperty');
const fSetConfigProperty = global.get('setConfigProperty');
const removeSpacesAroundDots = global.get('removeSpacesAroundDots');
const nConvertSignetUnsignet = global.get('nConvertSignetUnsignet');
const mExtractTime = global.get('mExtractTime');
const sExtractTime = global.get('sExtractTime');
const sCounty_Code = global.get('sCounty_Code');
const sTZidentifier = global.get('sTZidentifier');
const spotTresholdPrice = fGetConfigProperty("spotTresholdPrice") || 0; //dotaz na data z globalni strukturu


try {
    if (removeSpacesAroundDots && sExtractTime && sCounty_Code && sTZidentifier && nConvertSignetUnsignet && mExtractTime && fGetConfigProperty && fSetConfigProperty) {
        let nSet_Grid_Point = 0;

        // Definice fazi AC LOAD
        //Nejprve nacte data z MODBUSu, pokud je neplatna hodnota, tak nečte poslední známou hodnotu a pokud i ta neexistuje, tak vysledek je hodnota 0.
        const phase1 = (parseFloat(msg.payload.phase1) || global.get('phase1')) ?? 0; // Hodnota z registru 817
        const phase2 = (parseFloat(msg.payload.phase2) || global.get('phase2')) ?? 0;  // Hodnota z registru 818
        const phase3 = (parseFloat(msg.payload.phase3) || global.get('phase3')) ?? 0;  // Hodnota z registru 819

        // Definice Gridu
        //Nejprve nacte data z MODBUSu, pokud je neplatna hodnota, tak nečte poslední známou hodnotu a pokud i ta neexistuje, tak vysledek je hodnota 0.
        const grid1 = fCheckValue(nConvertSignetUnsignet(parseFloat(msg.payload.grid1)), 10, "grid1"); // Hodnota z registru 811
        const grid2 = fCheckValue(nConvertSignetUnsignet(parseFloat(msg.payload.grid2)), 10, "grid2"); // Hodnota z registru 812
        const grid3 = fCheckValue(nConvertSignetUnsignet(parseFloat(msg.payload.grid3)), 10, "grid3"); // Hodnota z registru 813

        // Definice vyroby FV panelu
        //Nejprve nacte data z MODBUSu, pokud je neplatna hodnota, tak nečte poslední známou hodnotu a pokud i ta neexistuje, tak vysledek je hodnota 0.
        const pvPower = fCheckValue(parseFloat(msg.payload.totalPVPower), 10, "pvPower"); // Hodnota z registru 819

        // Definice stavu nabiti baterie
        //Nejprve nacte data z MODBUSu, pokud je neplatna hodnota, tak nečte poslední známou hodnotu a pokud i ta neexistuje, tak vysledek je hodnota 0.
        const nBattery_State_Charge = (parseFloat(msg.payload.nBattery_State_Charge) || global.get('nBattery_State_Charge')) ?? 0;  // Hodnota z registru 843 v %//SOC
        const nBattery_Power = (parseFloat(msg.payload.nBattery_Power) || global.get('nBattery_Power')) ?? 0; // Battery Power (System) 842 ve W
        const nBattery_Current = (parseFloat(msg.payload.nBattery_Current) || global.get('nBattery_Current')) ?? 0; // Battery Power (System) 841 v A DC
        const nBattery_Voltage = (parseFloat(msg.payload.nBattery_Voltage) || global.get('nBattery_Voltage')) ?? 0; // Battery Power (System) 840 v V DC
        const nESS_BatteryLife_SoC_limit = (parseFloat(msg.payload.nESS_BatteryLife_SoC_limit) || global.get('nESS_BatteryLife_SoC_limit')) ?? 0; // ESS BatteryLife SoC limit (read only) 2903 v % 

        // Definice GET_Grid_Feed_2706 - Zaokrouhlení dolů	
        const nGET_Grid_Feed_2706 = Math.floor((parseFloat(msg.payload.nGrid_Feed_2706)) || global.get('nGET_Grid_Feed_2706'))*100 ?? 0;  // Hodnota z registru 2706 v W
        //Maximum System Grid Feed In:  -1: No limit, >=0: limited system feed-in. Applies to DC-coupled and AC-coupled feed-in.

        // Pole dnesniho spotu
        const todayHourlyPrices = global.get("todayHourlyPrices");

        let nSignet_Battery_Power = nConvertSignetUnsignet(nBattery_Power);

        // Ulozeni dat do globalnich promennych, ktere jsou dostupne mezi flow
        global.set("phase1", phase1);
        global.set("phase2", phase2);
        global.set("phase3", phase3);
        global.set("pvPower", pvPower);
        global.set("nBattery_State_Charge", nBattery_State_Charge);
        global.set("nESS_BatteryLife_SoC_limit", nESS_BatteryLife_SoC_limit);
        global.set("grid1", grid1);
        global.set("grid2", grid2);
        global.set("grid3", grid3);
        global.set("nBattery_Power", nBattery_Power);
        global.set("nBattery_Current", nBattery_Current);
        global.set("nBattery_Voltage", nBattery_Voltage);
        global.set("nGET_Grid_Feed_2706", nGET_Grid_Feed_2706);


        // Načteni globalnich dat
        const switchSpotGridCharging = !!fGetConfigProperty("switchSpotGridCharging"); // true znamena zapnut přepinač switchSpotGridCharging.        
        const nCharging_DurationGRID = fGetConfigProperty("nCharging_DurationGRID") || 0; // Nastav počet hodin nabíjení z GRIDu.         
        const nAcceptable_Price_GRID = fGetConfigProperty("nAcceptable_Price_GRID") || 0; // akceptovatelna cena Spotu pro nabijeni z GRIDu. 
        const nBalancingReserve = fGetConfigProperty("nBalancingReserve") || 0; // Hodnota ve W. Slouží k vyrovnávání výkonu, aby se zamezilo kolísání.
        const nGridConsumptionEnable = !!fGetConfigProperty("nGridConsumptionEnable"); // true znamena zapnut přepinač NUCENY ODBER Z GRIDu
        const nSetGridValue = fGetConfigProperty("nSetGridValue") || 0; // nastavevi v UI SetPoint
        //const isSpotAutoCtrlEnabled = !!fGetConfigProperty("isSpotAutoCtrlEnabled"); // true znamená Automaticky podle SPOTu
        const spotTresholdPrice = fGetConfigProperty("spotTresholdPrice") || 0; // Limitni cena
        const switchDelayCharging = !!fGetConfigProperty("switchDelayCharging"); // true znamena ze je aktivovana funkce posunuti nabijeni baterie
        const tStartBattery = fGetConfigProperty("tStartBattery") || 0; // Zadany cas start posunu nabijeni beterie
        const tStopBattery = fGetConfigProperty("tStopBattery") || 0; // Zadany cas stop posunu nabijeni beterie
        const nMorningPeakBatterySales = !!fGetConfigProperty("nMorningPeakBatterySales"); // Switch Prodej baterie v ranní špičce
        const nEveningPeakBatterySales = !!fGetConfigProperty("nEveningPeakBatterySales"); // Switch Prodej baterie ve večerní špičce
        const nMorningSOC_sales = fGetConfigProperty("nMorningSOC_sales") || 0; // Procenta - Prodej Rano do SOC
        const nEveningSOC_sales = fGetConfigProperty("nEveningSOC_sales") || 0; // Procenta - Prodej Večer do SOC
        const nMAX_Grid_Point = fGetConfigProperty("nMAX_Grid_Point") || 0; // Maximalní vybijecí proud ve W
        const sGridChargingSwitch = !!fGetConfigProperty("sGridChargingSwitch"); // Switch Nabijeni beterie z Gridu
        const nGridChargingSOC = fGetConfigProperty("nGridChargingSOC") || 0; // Procenta - Nabiti baterie z GRIDU do SOC
        // Switch pro inekráž ele.i z FW panelů. Energii dodává na GRID jen tehdy, když je dostatek z pamenu
        // Minus užitečná zátěž, a do hodnory nastavené v AcPowerSetPoint (nSetGridValue). 
        // Funkce je proprietní, nepoužívat v jiních instalaci, pokud nevíte co délá. 
        const nEnergyThresholdInjector = !!fGetConfigProperty("nEnergyThresholdInjector");
        const nNonBatteryPriorityMode = !!fGetConfigProperty("nNonBatteryPriorityMode");  //true je prioritizaci jiných zdrojů než baterie. Cílene pro nabijeni ElektroAuta
        const nSetPeak = fGetConfigProperty("nSetPeak") || 2; // Nastavení délky peaku pro prodej
        const nDynamicSOC_Reserve = !!fGetConfigProperty("nDynamicSOC_Reserve"); //Smart Morning Reserve Adjustment
        const nHouseHourlyConsumption = fGetConfigProperty("nHouseHourlyConsumption") || 0; // Průměrná hodinová spotřeba domu v klidovém režimu (% SOC za hodinu) - používá se pro výpočet potřebné rezervy baterie na noční provoz
        const nSunriseProductionOffset = fGetConfigProperty("nSunriseProductionOffset") || 0; // Časový posun od svítání do začátku dostatečné solární produkce (v hodinách) - kompenzuje skutečnost, že i po svítání může chvíli trvat, než solární panely pokryjí spotřebu domu
        const hSunData = global.get("sunData") || {}; // Sunrise-Sunset Processor;

        const nSOCDeltaBeforeExport_Switch = !!fGetConfigProperty("nSOCDeltaBeforeExport_Switch") || 0;
        const nSOCDeltaBeforeExport = fGetConfigProperty("nSOCDeltaBeforeExport") || 0;

        const currentPrice = global.get("currentPrice") || 0; // Aktualni SPOT cena
        const nPretoky = !!global.get("nPretoky"); // Pretoky povoleny- true, zakazany - false


        const currentTime = new Date(); // aktualni cas
        const sDate = currentTime.toLocaleString(sCounty_Code, { timeZone: sTZidentifier }); // prida CZ lokaci

        const oDate_CZ = sExtractTime(removeSpacesAroundDots(sDate)); // upravi stavajici obekt cas na prijatelnou podobu pro porovnavani

        const tStartBatteryTime = mExtractTime(tStartBattery); // vstupni promenna je jen milisekundy a nejde porovnavat s aktualnim casem, tak opet uprava na prijatelnou podobu pro porovnavani.
        const tStopBatteryTime = mExtractTime(tStopBattery);

        // Spočítat celkový odběr AC zátěže
        let totalACLoad = phase1 + phase2 + phase3;

        //Zjisti skutečnou délku pole, standartně je 24 prvků.
        const arrayLengthPrices = checkArrayLength(todayHourlyPrices, EXPECTED_ARRAY_LENGTH);
        // Hleda ranni a odpoleni peaky
        // prvni promenna je pole aktualniho spot a druha promenna rika jak dlouhy peak muse bejt
        const morningPeak1 = findMorningPeakHours(todayHourlyPrices, arrayLengthPrices, nSetPeak);
        const afternoonPeak1 = findAfternoonPeakHours(todayHourlyPrices, arrayLengthPrices, nSetPeak);
        global.set("morningPeak", morningPeak1);
        global.set("afternoonPeak",afternoonPeak1);

        // Vypočítá upravený SOC pro ranní rezervu baterie na základě času do východu slunce
        let nMorningSOC_salesCopie = 0;
        if (calculateSmartMorningReserve(morningPeak1, oDate_CZ, hSunData, nSunriseProductionOffset, nHouseHourlyConsumption, debug)) {
            nMorningSOC_salesCopie = nMorningSOC_sales + global.get("requiredTimeOffsetEnd") || 0; // Vypočítá upravený SOC pro ranní rezervu baterie na základě času do východu slunce
            }

        let nZbytekFV = pvPower - (totalACLoad + nBalancingReserve);
        nSet_Grid_Point = fSet_Grid(nGridConsumptionEnable, nSetGridValue, currentPrice);    

        //node.warn("switchSpotGridCharging1: " + switchSpotGridCharging); 
        if ((!sGridChargingSwitch) && (!switchSpotGridCharging)){// neni zapnuta funkce na nabijeni baterie z GRIDu a nebo SPOTu
            if (nPretoky == true) { // povolene pretoky

                //Funkce inektaž na GRID podle výkonu FV úanelů
                if (nEnergyThresholdInjector == true) {//true -> zapnutá inektaž na GRID podle výkonu FV. 
                    if (currentPrice > 0) {// Dokud neni zaporný spot
                        if (nZbytekFV > 0 && nSetGridValue < 0) {//Zbytek je vetsí nez nastaena hodnota.
                           //Tato podmínka kontroluje dvě věci:
                                //nZbytekFV je větší než nula, což znamená, že je to kladná hodnota.
                                //nSetGridValue je menší než nula, což znamená, že je to záporná hodnota.
                           //node.warn("nZbytekFV: " + nZbytekFV);
                            //node.warn("nSetGridValue: " + nSetGridValue);
                            nSet_Grid_Point = nSetGridValue;  //nastav nastavenou hodnotu na nSet_Grid_Point.
                        }
                    }
                }
                //Funkce na posunutí nabíjení baterie
                if (switchDelayCharging == true) { // true znamena ze je aktivovana funkce posunuti nabijeni baterie
                    let shouldProceed = true;
                    if (nSOCDeltaBeforeExport_Switch == true) {// true znamena ze je aktivovana funkce SOC delta před exportem
                        // Funkce bude aktivní pouze když SOC baterie dosáhne požadované hodnoty
                        if (nBattery_State_Charge <= nSOCDeltaBeforeExport) {
                            shouldProceed = false; // SOC není dostatečně nabitý, funkce nebude aktivní
                        }
                    } else shouldProceed = true; // neni pozadováno podle SOC, tak bude funkce normalne funkci
                    if (shouldProceed) {
                        if (tStartBatteryTime && tStopBatteryTime) {
                            if (oDate_CZ >= tStartBatteryTime && oDate_CZ <= tStopBatteryTime) { // Aktuální čas je v rozsahu
                                if (nZbytekFV > 0) { // Prebytek FV je kladna hodnota
                                    nSet_Grid_Point = -nZbytekFV; // prevest na zapornou hodnotu
                                } else { // mala vyroba z FV panelu
                                    if (currentPrice > 0) {// Dokud neni zaporný spot
                                        //nedelej nic s registrem nSet_Grid_Point - regist je nastaven pomoci funkce fSet_Grid, dokud ji jine nastaveni nezmeni
                                    } else {nSet_Grid_Point = 0;}// vynuluj registr
                                }
                            } else { // Aktuální čas je mimo rozsah
                                // nSet_Grid_Point = fSet_Grid(nGridConsumptionEnable, nSetGridValue, isSpotAutoCtrlEnabled, spotTresholdPrice, currentPrice, nPretoky, nMAX_Grid_Point);
                            }
                        } else { // Čas začátku nebo konce není nastaven
                            nSet_Grid_Point = 0;
                        }
                     }
                }
            }

            // funkce vybití baterie při ranní špičce             
            if (nMorningPeakBatterySales) {                 
                if (morningPeak1.length > 0) {                     
                    const peakTimeStart = new Date(oDate_CZ.getFullYear(), oDate_CZ.getMonth(), oDate_CZ.getDate(), morningPeak1[0], 0, 0, 0);                     
                    const peakTimeEnd = new Date(oDate_CZ.getFullYear(), oDate_CZ.getMonth(), oDate_CZ.getDate(), morningPeak1[morningPeak1.length - 1], 59, 0, 0);                      

                    if (oDate_CZ >= peakTimeStart && oDate_CZ < peakTimeEnd) {                                               
                        let nPosunutiSOC = nMorningSOC_sales;
                        if (nDynamicSOC_Reserve == true) { // povolena funkce Smart Morning Reserve Adjustment                              
                            nPosunutiSOC = nMorningSOC_salesCopie;
                        }                           

                        if (nBattery_State_Charge >= nPosunutiSOC) {                             
                            if (nPretoky == true) { // povolene pretoky                                                                                                                            
                                if (currentPrice >= spotTresholdPrice) {// Prodávat do nastavené hodnoty v spotTresholdPrice                                     
                                    nSet_Grid_Point = EnsureNegativeValue(nMAX_Grid_Point);                                 
                                }                             
                            }                         
                        }                     
                    }                                     
                }             
            }

            // funkce vybití baterie při večerní  špičce
            if (nEveningPeakBatterySales) {
                if (afternoonPeak1.length > 0) {
                    const peakTimeStart = new Date(oDate_CZ.getFullYear(), oDate_CZ.getMonth(), oDate_CZ.getDate(), afternoonPeak1[0], 0, 0, 0);
                    const peakTimeEnd = new Date(oDate_CZ.getFullYear(), oDate_CZ.getMonth(), oDate_CZ.getDate(), afternoonPeak1[afternoonPeak1.length - 1], 59, 0, 0);

                    if (debug) {
                        //node.warn("-----------------------------------------");
                        //node.warn("global.get(afternoonPeak1): " + afternoonPeak1);
                        //node.warn("peakTimeStart: " + peakTimeStart);
                        //node.warn("peakTimeEnd: " + peakTimeEnd);
                        //node.warn("oDate_CZ: " + oDate_CZ);
                        //node.warn("global.get(nBattery_State_Charge): " + nBattery_State_Charge);
                        //node.warn("nSet_Grid_Point: " + nSet_Grid_Point);
                    }

                    if (oDate_CZ >= peakTimeStart && oDate_CZ < peakTimeEnd) {
                        if (nBattery_State_Charge >= nEveningSOC_sales) {
                            if (nPretoky == true) { // povolene pretoky
                                if (currentPrice >= spotTresholdPrice) {// Prodávat do nastavené hodnoty v spotTresholdPrice
                                    nSet_Grid_Point = EnsureNegativeValue(nMAX_Grid_Point);
                                }
                            }
                        }
                    }
                }
            }

            //nNonBatteryPriorityMode - Nabijeni elekto auta
            if (nNonBatteryPriorityMode) {
                // Zajistí, že výsledek bude vždy kladný (nebo nula)
                //const nRozdil = pvPower - (totalACLoad + (nBalancingReserve ));
                //Obraceni znamenka
                const nBatteryPower = -nSignet_Battery_Power;
                const nRozdil = pvPower - (totalACLoad + nBatteryPower);

                if (debug) {
                       // node.warn("nRozdil : " + nRozdil);
                       // node.warn("nBatteryPower : " + nBatteryPower);
                       // node.warn("pvPower : " + pvPower);
                       // node.warn("totalACLoad : " + totalACLoad);
                    }

                if (nRozdil < 0){//vysledek je zaporny
                    nSet_Grid_Point = Math.abs(nRozdil); // Převod na absolutní hodnotu (vždy kladné číslo)
                }
            }

        } else {   

            if (sGridChargingSwitch){// Zapnuta funkce nabijeni baterie z gridu, nabiji do nastaveneho SOC, pak vypne nabijení :).
                //nGridChargingSOC
                if (nBattery_State_Charge < nGridChargingSOC) {
                    nSet_Grid_Point = EnsurePositiveValue(nMAX_Grid_Point);
                }else {//vypnout nabijeni
                fSetConfigProperty("sGridChargingSwitch", false); //vypne nabijeni aby nebylo kminání (urdřování baterie na SOC tato funkce neřeší)
                }
                if (debug) {
                            //node.warn("-----------------------------------------");
                            //node.warn("nBattery_State_Charge: " + nBattery_State_Charge);
                            //node.warn("nGridChargingSOC: " + nGridChargingSOC);
                        }
            }

            if (switchSpotGridCharging) { //Zapnuta funkce nabijeni baterie z Gridu podle SPOtu
                const aFindPeakSPOT = findCheapestContinuousBlock(todayHourlyPrices, arrayLengthPrices, nCharging_DurationGRID);
                global.set("arrSPOT_GRIF_Peak",aFindPeakSPOT);
                //node.warn("aFindPeakSPOT: " + aFindPeakSPOT);
                if (aFindPeakSPOT.length > 0) {                     
                    const peakTimeStart = new Date(oDate_CZ.getFullYear(), oDate_CZ.getMonth(), oDate_CZ.getDate(), aFindPeakSPOT[0], 0, 0, 0);                     
                    const peakTimeEnd = new Date(oDate_CZ.getFullYear(), oDate_CZ.getMonth(), oDate_CZ.getDate(), aFindPeakSPOT[aFindPeakSPOT.length - 1], 59, 0, 0);                      

                    if (oDate_CZ >= peakTimeStart && oDate_CZ < peakTimeEnd) {   

                        if (currentPrice <= nAcceptable_Price_GRID){// Nakupovat do nastavené hodnoty v nAcceptable_Price_GRID  
                            //node.warn("nabijim: " + nMAX_Grid_Point);                                   
                            nSet_Grid_Point = EnsurePositiveValue(nMAX_Grid_Point);                                                                                   
                        }                     
                    }                                     
                }  
            }
        }

        // Nastavit celkový odběr jako novou hodnotu pro nastavení sítě
        msg.payload = { "nSet_Grid_Point": nSet_Grid_Point,
                        "nGET_Grid_Feed_2706": nGET_Grid_Feed_2706,
                        "pvPower": pvPower,
                        "nMAX_Grid_Point": nMAX_Grid_Point,
                        "totalACLoad": totalACLoad,
