                        };

        } else {// nenalezeny globalni funkce
        node.error("Globální funkce nebyly nalezeny. <-- FORM BATTERY CONTROL-- AC LOAD");
    }
    return msg;
} catch (error) {
    node.error("Error in script: " + error.message);
}

// Oprava validnich dat z MBUSu, pokud bude X krat po sobe nula, tak vysledek bude nula, pokud bude nula 1x a min nez trigger, 
// tak se vezme hodnota z globalniho buffru
function fCheckValue(pvPowerReading, readingCount, globalVarName) {
    // Dynamicky vytvoří název čítače na základě globalVarName
    let zeroReadingsCountKey = `${globalVarName}_Count`;

    // Získá dynamicky čítač a počáteční hodnotu výkonu z globálních proměnných
    let zeroReadingsCount = global.get(zeroReadingsCountKey) || 0;
    let pvPower = global.get(globalVarName) ?? 0; // Defaultně nastavíme na 0, pokud není dostupná globální hodnota

    if (pvPowerReading === 0) {
        // Zvýšení čítače, pokud byla přečtena hodnota 0
        zeroReadingsCount += 1;

        if (zeroReadingsCount >= readingCount) {
            // Pokud čítač dosáhne požadovaného počtu, nastavíme pvPower na 0
            pvPower = 0;
            zeroReadingsCount = 0; // Resetování čítače
        }
    } else if (pvPowerReading === null) {
        // Pokud je čtení neplatné, použijeme globální proměnnou
        zeroReadingsCount = 0; // Reset čítače, pokud čtení nebylo 0
    } else {
        // Pokud je čtení platné a nenulové, používáme ho
        pvPower = pvPowerReading;
        zeroReadingsCount = 0; // Reset čítače, pokud čtení nebylo 0
    }

    // Uložení dynamicky generovaného čítače zpět do globální proměnné
    global.set(zeroReadingsCountKey, zeroReadingsCount);
    // Uložení dynamicky generované hodnoty výkonu zpět do globální proměnné
    global.set(globalVarName, pvPower);

    return pvPower;
}

