// Tato funkce vypočítá medián zadaných hodnot
function calculateMedian(values) {
    values = values.slice().sort((a, b) => a - b);
    const mid = Math.floor(values.length / 2);

    if (values.length % 2 === 0) {
        return (values[mid - 1] + values[mid]) / 2;
    } else {
        return values[mid];
    }
}


// Funkce pro výpis pole
function printArray(array) {
    return `[${array.join(', ')}]`;
}

// Funkce pro kontrolu počtu prvků v poli
function checkArrayLength(array, expectedLength) {
    const actualLength = array.length;
    if (debug) {
        if (actualLength !== expectedLength) {
            node.error(`Pole neobsahuje očekávaný počet prvků. Očekáváno: ${expectedLength}, obdrženo: ${actualLength}`);
            node.error(`Obsah pole: ${printArray(array)}`);
        }
    }
    return actualLength;
}

// Tyto funkce používají calculateMedian k určení prahové hodnoty pro ranní a odpolední hodiny
// Funkce pro hledání ranní špičky
function findMorningPeakHours(hourlyValues, arrayLength = EXPECTED_ARRAY_LENGTH, maxPeakLength = 2) {
    // omezení na maximum:  // Ořež na max 4
    if (maxPeakLength > 4) {maxPeakLength = 4; }

    if (hourlyValues.length !== arrayLength) {
        throw new Error(`Function: findMorningPeakHours -> Array must contain exactly ${arrayLength} elements.`);
    }

    // Výpočet mediánu pro první polovinu dne
    const halfLength = Math.floor(arrayLength / 2);
    const peakThreshold = calculateMedian(hourlyValues.slice(0, halfLength));
    let morningPeakHours = [];

    // Najít ranní špičku (0 do poloviny dne)
    for (let i = 0; i < halfLength; i++) {
        if (hourlyValues[i] >= peakThreshold) {
            morningPeakHours.push(i);
        }
    }

    return findContinuousBlocks(morningPeakHours, maxPeakLength, hourlyValues);
}

// Funkce pro hledání odpolední špičky
function findAfternoonPeakHours(hourlyValues, arrayLength = EXPECTED_ARRAY_LENGTH, maxPeakLength = 2) {
    // omezení na maximum:  // Ořež na max 4
    if (maxPeakLength > 4) {maxPeakLength = 4; }

    if (hourlyValues.length !== arrayLength) {
        throw new Error(`Function: findAfternoonPeakHours -> Array must contain exactly ${arrayLength} elements.`);
    }

    // Výpočet mediánu pro druhou polovinu dne
    const halfLength = Math.floor(arrayLength / 2);
    const peakThreshold = calculateMedian(hourlyValues.slice(halfLength, arrayLength));
    let afternoonPeakHours = [];

    // Najít odpolední špičku (polovina dne do konce)
    for (let i = halfLength; i < arrayLength; i++) {
        if (hourlyValues[i] >= peakThreshold) {
            afternoonPeakHours.push(i);
        }
    }

    return findContinuousBlocks(afternoonPeakHours, maxPeakLength, hourlyValues);
}

// Tato funkce zjišťuje souvislé bloky hodin v daném poli a vrací nejdelší blok nebo prázdné pole
function findContinuousBlocks(hoursArray, maxPeakLength, values) {
    let blocks = [];
    let currentBlock = [];

    for (let i = 0; i < hoursArray.length; i++) {
        if (currentBlock.length === 0) {
            currentBlock.push(hoursArray[i]);
        } else if (hoursArray[i] === currentBlock[currentBlock.length - 1] + 1) {
            currentBlock.push(hoursArray[i]);
        } else {
            blocks.push(currentBlock);
            currentBlock = [hoursArray[i]];
        }
    }

    if (currentBlock.length > 0) {
        blocks.push(currentBlock);
    }

    // Najít nejdelší blok nebo vrátit prázdné pole, s maximální délkou bloku
    let longestBlock = blocks.reduce((a, b) => (a.length > b.length ? a : b), []);

    if (longestBlock.length > maxPeakLength) {
        let bestBlock = longestBlock.slice(0, maxPeakLength);
        let bestAvg = calculateAverage(bestBlock, values);

        for (let i = 1; i <= longestBlock.length - maxPeakLength; i++) {
            let currentBlock = longestBlock.slice(i, i + maxPeakLength);
            let currentAvg = calculateAverage(currentBlock, values);

            if (currentAvg > bestAvg) {
                bestBlock = currentBlock;
                bestAvg = currentAvg;
            }
        }

        return bestBlock;
    } else {
        return longestBlock;
    }
}

// Tato funkce vypočítá průměrnou hodnotu pro daný blok hodin
function calculateAverage(block, values) {
    let sum = block.reduce((acc, hour) => acc + values[hour], 0);
    return sum / block.length;
}

//funkce prevede kladne cislo na zaporne a ignoruje text a zapornou hodnotu ponecha bezezmeny..
function EnsureNegativeValue(inputValue) {
    // Check if the input is a number
    if (typeof inputValue === 'number') {
        // Ensure the value is negative
        if (inputValue > 0) {
            // Convert positive value to negative
            return -Math.abs(inputValue);
        } else {
            // Leave the value unchanged if it is already negative or zero
            return inputValue;
        }
    } else {
        // If the input is not a number, return 0
        return 0;
    }
}

//funkce prevede vstupni císlo na kladné a innoruje text
function EnsurePositiveValue(inputValue) {
    // Check if the input is a number
    if (typeof inputValue === 'number') {
        // Ensure the value is positive
        if (inputValue < 0) {
            // Convert negative value to positive
            return Math.abs(inputValue);
        } else {
            // Leave the value unchanged if it is already positive or zero
            return inputValue;
        }
    } else {
        // If the input is not a number, return 0
        return 0;
    }
}

/**
 * Vypočítá upravený SOC pro ranní rezervu baterie na základě času do východu slunce  
 * @param {Array} morningPeak - Pole obsahující hodiny (první prvek = hodina od které se počítá spotřeba)
 * @param {Date} currentTime - Aktuální čas 
 * @param {object} sunData - Data o východu/západu slunce (musí obsahovat sunrise.time) 
 * @param {number} sunriseProductionOffset - Časový posun od svítání do začátku dostatečné solární produkce (v hodinách) 
 * @param {number} houseHourlyConsumption - Průměrná hodinová spotřeba domu v klidovém režimu (% SOC za hodinu) 
 * @param {boolean} debug - Zapnout debug výstup 
 * @returns {boolean} true pokud výpočet proběhl úspěšně
 */
function calculateSmartMorningReserve(morningPeak, currentTime, sunData, sunriseProductionOffset, houseHourlyConsumption, debug) {
    // Kontrola struktury dat
    if (!sunData || !sunData.sun_data || !sunData.sun_data.sunrise || !sunData.sun_data.sunrise.time) {
        if (debug) {
            node.warn("Chybí data o východu slunce - sunData není kompletní");
        }
        return null;
    }

    // Kontrola morningPeak pole
    if (!morningPeak || !Array.isArray(morningPeak) || morningPeak.length === 0) {
        if (debug) {
            node.warn("morningPeak není platné pole");
        }
        return null;
    }

    let sunriseTime = sunData.sun_data.sunrise.date_object; // Načtení východu
    let sunriseHours = sunriseTime.getHours() + (sunriseTime.getMinutes() / 60);
    let currentHours = currentTime.getHours() + (currentTime.getMinutes() / 60);
    let nTimeEnd = sunriseHours + sunriseProductionOffset; // čas ukončení funkce
    let nTimeOffsetEnd = nTimeEnd - currentHours; // zbývající čas do konce funkce

    // Počáteční hodina pro výpočet spotřeby (z morningPeak pole)
    let batteryStartHour = morningPeak[0];

    if (debug) {
        node.warn("no korekce nTimeEnd: " + nTimeEnd);
        node.warn("no korekce nTimeOffsetEnd: " + nTimeOffsetEnd);
    }

    if (nTimeEnd < 0) { nTimeEnd = 0; } // korekce na záporné hodnoty
    if (nTimeOffsetEnd < 0) { nTimeOffsetEnd = 0; } // korekce na záporné hodnoty - zde ponecháváme 0 pro další výpočty

    // Výpočet spotřeby od zadané hodiny (ne od půlnoci)
    const hoursFromBatteryStart = Math.max(0, nTimeEnd - batteryStartHour);
    const requiredTimeEnd = hoursFromBatteryStart * houseHourlyConsumption;
    const requiredTimeOffsetEnd = nTimeOffsetEnd * houseHourlyConsumption;

    global.set("requiredTimeEnd", requiredTimeEnd);
    global.set("requiredTimeOffsetEnd", requiredTimeOffsetEnd);

    // batteryTimeEnd - absolutní čas ukončení (jen hodiny:minuty)
    const batteryTimeEndHours = Math.floor(nTimeEnd);
    const batteryTimeEndMinutes = Math.round((nTimeEnd % 1) * 60);
    const batteryTimeEndString = `${batteryTimeEndHours.toString().padStart(2, '0')}:${batteryTimeEndMinutes.toString().padStart(2, '0')}:00`;

    // batteryTimeOffsetEnd - kolik času zbývá do ukončení (může být i záporné)
    const originalNTimeOffsetEnd = (sunriseHours + sunriseProductionOffset) - currentHours; // počítáme znovu bez korekce na 0
    let batteryTimeOffsetEndString;

    if (originalNTimeOffsetEnd > 0) {
        // Zbývá čas - pozitivní hodnota
        const remainingHours = Math.floor(originalNTimeOffsetEnd);
        const remainingMinutes = Math.round((originalNTimeOffsetEnd % 1) * 60);
        batteryTimeOffsetEndString = `${remainingHours.toString().padStart(2, '0')}:${remainingMinutes.toString().padStart(2, '0')}:00`;
    } else if (originalNTimeOffsetEnd === 0) {
        batteryTimeOffsetEndString = "00:00:00";
    } else {
        // Čas už prošel - záporná hodnota
        const absOffset = Math.abs(originalNTimeOffsetEnd);
        const remainingHours = Math.floor(absOffset);
        const remainingMinutes = Math.round((absOffset % 1) * 60);
        batteryTimeOffsetEndString = `-${remainingHours.toString().padStart(2, '0')}:${remainingMinutes.toString().padStart(2, '0')}:00`;
    }

    global.set("batteryTimeEnd", batteryTimeEndString);
    global.set("batteryTimeOffsetEnd", batteryTimeOffsetEndString);

    if (debug) {
        node.warn("sunriseTime: " + sunriseTime);
        node.warn("nTimeEnd: " + nTimeEnd);
        node.warn("batteryStartHour: " + batteryStartHour);
        node.warn("originalNTimeOffsetEnd: " + originalNTimeOffsetEnd);
        node.warn("nTimeOffsetEnd: " + nTimeOffsetEnd);
        node.warn("hoursFromBatteryStart: " + hoursFromBatteryStart);
        node.warn("requiredTimeEnd: " + requiredTimeEnd.toFixed(2));
        node.warn("requiredTimeOffsetEnd: " + requiredTimeOffsetEnd.toFixed(2));
        node.warn("batteryTimeEnd: " + batteryTimeEndString);
        node.warn("batteryTimeOffsetEnd: " + batteryTimeOffsetEndString);
    }
    return true;
}

/**
 * Funkce najde nejlevnější souvislý blok hodin zadané délky
 * @param {Array} todayHourlyPrices - Pole spotových cen (obvykle 24 hodin, ale může být 23 nebo 25 při změně času)
 * @param {number} arrayLengthPrices - Skutečná délka pole (23, 24, nebo 25)
 * @param {number} requiredChargingHours - Požadovaná doba nabíjení v hodinách, max 20 hodin
 * @returns {Array} Pole hodin nejlevnějšího souvislého bloku - VŽDY vrací nějaký výsledek
 */
function findCheapestContinuousBlock(todayHourlyPrices, arrayLengthPrices, requiredChargingHours) {
    // omezení na maximum:  // Ořež na max 20
    //if (requiredChargingHours > 20) {requiredChargingHours = 20; }

    // Základní validace - pokud nejsou platná data, vrátíme první hodiny
    if (!Array.isArray(todayHourlyPrices) || todayHourlyPrices.length !== arrayLengthPrices) {
        let fallbackBlock = [];
        for (let i = 0; i < Math.min(requiredChargingHours, arrayLengthPrices); i++) {
            fallbackBlock.push(i);
        }
        return fallbackBlock;
    }

    // Pokud je požadovaná délka větší než skutečná délka pole, omezíme na délku pole
    if (requiredChargingHours > arrayLengthPrices) {
        requiredChargingHours = arrayLengthPrices;
    }

    // Pokud je požadovaná délka neplatná, nastavíme na 1 hodinu
    if (requiredChargingHours <= 0) {
        requiredChargingHours = 1;
    }

    let bestBlock = [];
    let bestTotalPrice = Infinity;

    // Procházíme všechny možné pozice pro začátek bloku
    for (let startHour = 0; startHour <= arrayLengthPrices - requiredChargingHours; startHour++) {
        let currentBlock = [];
        let totalPrice = 0;

        // Vytvoříme blok požadované délky
        for (let i = 0; i < requiredChargingHours; i++) {
            let hourIndex = startHour + i;
            currentBlock.push(hourIndex);
            totalPrice += todayHourlyPrices[hourIndex];
        }

        // Porovnáme celkovou cenu s dosud nejlepší (hledáme nejlevnější celistvý úsek)
        if (totalPrice < bestTotalPrice) {
            bestTotalPrice = totalPrice;
            bestBlock = currentBlock.slice();
        }
    }

    // VŽDY vrátíme nějaký blok - pokud se něco pokazilo, vrátíme první hodiny
    if (bestBlock.length === 0) {
        for (let i = 0; i < requiredChargingHours; i++) {
            bestBlock.push(i);
        }
    }

    return bestBlock;
}

