const fSetConfigProperty = global.get('setConfigProperty');

try {
    const config = JSON.parse(msg.payload);  // Pokusit se parsovat JSON
    //global.set('config', config);          // Uložit konfiguraci do globální proměnné

    // Zjistit odkud pochazi pozadavek na nahrani konfigurace
    if (msg.load === "LOAD_CONFIG_API") {
        // kdyz je ztracen jen token, tak ulozit jen token a zbytek ignorovat
        if (config.bearerToken) {
