// Funkce pro formátování pole na krátký text (max 15 znaků)
function formatPeakHours(peakArray) {
    if (Array.isArray(peakArray) && peakArray.length > 0) {
        const firstHour = peakArray[0];
        const lastHour = peakArray[peakArray.length - 1];

        if (peakArray.length === 1) {
            return `[${firstHour}h]`;
        } else {
            return `[${firstHour}h-${lastHour}h]`;
        }
    } else {
        return "[Žádný]";
    }
}

const formattedMorning = formatPeakHours(morningPeak);
const formattedAfternoon = formatPeakHours(afternoonPeak);

if (debug) {
    node.warn("morningPeak pole: " + JSON.stringify(morningPeak));
    node.warn("afternoonPeak pole: " + JSON.stringify(afternoonPeak));
    node.warn("Formátované ráno: " + formattedMorning + " (" + formattedMorning.length + " znaků)");
    node.warn("Formátované odpoledne: " + formattedAfternoon + " (" + formattedAfternoon.length + " znaků)");
}

msg.payload = { 
    morningPeak: formattedMorning,
    afternoonPeak: formattedAfternoon
};

return msg;

