//*****************************************************************************
//
// File Name        : Sunrise-Sunset Response Processor
// Title            : Zpracování odpovědi z Sunrise-Sunset API
// Author           : http://www.prochazka.zde.cz
// Created          : 16-06-2025, 21:00
// Revised          : 20-06-2025, 17:43
// Version          : 1.2
// Target Platform  : Node-RED
//
// SUNRISE-SUNSET.ORG API VYSVĚTLENÍ:
// ==================================
// API VŽDY vrací časy v UTC (Coordinated Universal Time), i když posíláte timezone!
// Důvod: API je navrženo pro jednoduchost - pracuje pouze s GPS souřadnicemi a datem.
// Časovou zónu si musíte převést sami na straně klienta.
//
// VÝZNAM VŠECH HODNOT Z API ODPOVĚDI:
// -----------------------------------
// sunrise:                    Východ slunce (spodní okraj slunce se objeví na obzoru)
// sunset:                     Západ slunce (spodní okraj slunce zmizí za obzorem)
// solar_noon:                 Sluneční poledne (slunce je nejvýše na obloze)
// day_length:                 Délka dne v sekundách (od východu do západu slunce)
// civil_twilight_begin:       Začátek občanského soumraku (slunce 6° pod obzorem ráno)
// civil_twilight_end:         Konec občanského soumraku (slunce 6° pod obzorem večer)
// nautical_twilight_begin:    Začátek námořního soumraku (slunce 12° pod obzorem ráno)
// nautical_twilight_end:      Konec námořního soumraku (slunce 12° pod obzorem večer)
// astronomical_twilight_begin: Začátek astronomického soumraku (slunce 18° pod obzorem ráno)
// astronomical_twilight_end:   Konec astronomického soumraku (slunce 18° pod obzorem večer)
//
// POZNÁMKY K SOUMRAKŮM:
// - Občanský soumrak: Stále je dostatek světla pro běžné aktivity venku
// - Námořní soumrak: Horizont je stále viditelný, hvězdy začínají být vidět
// - Astronomický soumrak: Je dostatečně tmavé pro astronomická pozorování
// - V létě na vysokých zeměpisných šířkách může astronomical twilight "neexistovat"
//   (slunce nikdy neklesne 18° pod obzor) - pak API vrací "1970-01-01T00:00:01+00:00"
//
// ČASOVÉ FORMÁTY:
// - Všechny časy jsou v ISO 8601 formátu: "YYYY-MM-DDTHH:MM:SS+00:00"
// - "+00:00" označuje UTC timezone (Greenwich Mean Time)
// - Pro konverzi do lokálního času použijte JavaScript Date() objekt s toLocaleString()
//
// This code is distributed under the GNU Public License
// Všechny informace jsou zahrnuty pod GPL licenci, pokud není explicitně uveden jiný typ licence.
// Používání těchto stránek a produktů ke komerčním účelům lze jen se souhlasem autora.
// Všechna práva vyhrazena (c) 1997 - 2025 hacesoft.
//
//*****************************************************************************

// Debugging flag
const debug = false;  // Nastavte na true pro zapnutí debug zpráv

// Načtení timezone parametrů z globálních proměnných
const sCounty_Code = global.get('sCounty_Code');
const sTZidentifier = global.get('sTZidentifier');

// Kontrola úspěšné odpovědi
if (msg.statusCode !== 200) {
    if (debug) {
        node.warn("Chyba HTTP statusCode: " + msg.statusCode);
    }
    return msg;
}

if (!msg.payload || !msg.payload.results) {
    if (debug) {
        node.warn("Chyba: Chybí payload nebo results");
    }
    return msg;
}

if (!msg.payload.results || msg.payload.status !== "OK") {
    if (debug) {
        node.warn("Chyba API status: " + msg.payload.results.status);
    }
    return msg;
}

try {
    const results = msg.payload.results;

    // Zpracování všech časů z API odpovědi s popisy
    const sunData = {
        sunrise: {
            ...convertUTCToLocal(results.sunrise),
            description: "Východ slunce (spodní okraj slunce se objeví na obzoru)"
        },
        sunset: {
            ...convertUTCToLocal(results.sunset),
            description: "Západ slunce (spodní okraj slunce zmizí za obzorem)"
        },
        solar_noon: {
            ...convertUTCToLocal(results.solar_noon),
            description: "Sluneční poledne (slunce je nejvýše na obloze)"
        },
        day_length: {
            ...formatDayLength(results.day_length),
            description: "Délka dne (od východu do západu slunce)"
        },
        civil_twilight_begin: {
            ...convertUTCToLocal(results.civil_twilight_begin),
            description: "Začátek občanského soumraku (slunce 6° pod obzorem ráno)"
        },
        civil_twilight_end: {
            ...convertUTCToLocal(results.civil_twilight_end),
            description: "Konec občanského soumraku (slunce 6° pod obzorem večer)"
        },
        nautical_twilight_begin: {
            ...convertUTCToLocal(results.nautical_twilight_begin),
            description: "Začátek námořního soumraku (slunce 12° pod obzorem ráno)"
        },
        nautical_twilight_end: {
            ...convertUTCToLocal(results.nautical_twilight_end),
            description: "Konec námořního soumraku (slunce 12° pod obzorem večer)"
        },
        astronomical_twilight_begin: {
            ...convertUTCToLocal(results.astronomical_twilight_begin),
            description: "Začátek astronomického soumraku (slunce 18° pod obzorem ráno)"
        },
        astronomical_twilight_end: {
            ...convertUTCToLocal(results.astronomical_twilight_end),
            description: "Konec astronomického soumraku (slunce 18° pod obzorem večer)"
        }
    };

    // Příprava výstupního payloadu
    msg.payload = {
        success: true,
        timezone: sTZidentifier,
        country_code: sCounty_Code,
        sun_data: sunData,
        quick_access: {
            sunrise: sunData.sunrise ? sunData.sunrise.time : "N/A",
            sunset: sunData.sunset ? sunData.sunset.time : "N/A",
            solar_noon: sunData.solar_noon ? sunData.solar_noon.time : "N/A",
            day_length: sunData.day_length.formatted
        }
    };

    // Uložení do global proměnných pro snadné použití
    global.set("sunData", msg.payload);

    if (debug) {
        node.warn("Sunrise data zpracována:");
        node.warn("Východ slunce: " + (sunData.sunrise ? sunData.sunrise.time : "N/A"));
        node.warn("Západ slunce: " + (sunData.sunset ? sunData.sunset.time : "N/A"));
        node.warn("Délka dne: " + sunData.day_length.formatted);
        node.warn("Časová zóna: " + sTZidentifier);
    }

} catch (error) {
    node.error("Chyba při zpracování Sunrise-Sunset dat: " + error.message);
    msg.payload = {
        success: false,
        error: "Chyba při zpracování dat",
        message: error.message
    };
}

return msg;

    // Funkce pro převod UTC času do lokální časové zóny
    function convertUTCToLocal(utcTimeString) {
        // Kontrola neplatných časů - astronomical twilight v létě na vysokých šířkách
        // může "neexistovat" (slunce nikdy neklesne 18° pod obzor)
        if (!utcTimeString || utcTimeString === "1970-01-01T00:00:01+00:00") {
            return null; // API vrací datum 1970 jako indikátor neexistence soumraku
        }

        const utcDate = new Date(utcTimeString);

        // Převod do lokálního času
        const localTime = utcDate.toLocaleString(sCounty_Code, {
            timeZone: sTZidentifier,
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: '2-digit',
            minute: '2-digit',
            second: '2-digit'
        });

        // Pouze čas ve formátu HH:MM:SS
        const timeOnly = utcDate.toLocaleTimeString(sCounty_Code, {
            timeZone: sTZidentifier,
            hour: '2-digit',
            minute: '2-digit',
            second: '2-digit'
        });

        return {
            full: localTime,
            time: timeOnly,
            utc: utcTimeString,
            date_object: utcDate
        };
    }

// Funkce pro převod sekund na čitelný formát
function formatDayLength(seconds) {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const remainingSeconds = seconds % 60;

    return {
        hours: hours,
        minutes: minutes,
        seconds: remainingSeconds,
        formatted: `${hours}h ${minutes}m ${remainingSeconds}s`
    };
}

