//
//*****************************************************************************
// Debugging flag
const debug = false;  // Nastavte na true pro zapnutí debug zpráv

// Načtení vstupu
const data = msg.payload;
// Načtení timezone parametrů z globálních proměnných
const sCounty_Code = global.get('sCounty_Code');
const sTZidentifier = global.get('sTZidentifier');

// Kontrola úspěšné odpovědi
if (msg.statusCode !== 200 || !data.success) {
    if (debug) {
        node.warn("VRM API chyba - statusCode: " + msg.statusCode + ", success: " + data.success);
    }
    return msg;
}

let latitude = null;
let longitude = null;

// Prohledání records pole
for (let record of data.records) {
    if (record.Device === "Gateway" && record.dbusServiceType === "gps") {
        if (record.description === "Latitude") {
            latitude = record.rawValue;
        }
        if (record.description === "Longitude") {
            longitude = record.rawValue;
        }
    }
}

// Uložení do flow proměnných
if (latitude !== null && longitude !== null) {
    flow.set("Latitude", latitude);
    flow.set("Longitude", longitude);
    if (debug) {
        node.warn("GPS souřadnice uloženy - Lat: " + latitude + ", Lng: " + longitude);
    }
    // Získání aktuálního data
    const todayDate = getTodayDateString();
    const localizedDate = getLocalizedDate();

    // Příprava URL pro Sunrise-Sunset API - manuální sestavení parametrů
    const baseUrl = "https://api.sunrise-sunset.org/json";
    const urlParams = `lat=${latitude}&lng=${longitude}&date=${todayDate}&formatted=0`;
    const fullUrl = `${baseUrl}?${urlParams}`;

    // Nastavení HTTP requestu
    msg.url = fullUrl;
    msg.method = "GET";
    msg.headers = {
        "Content-Type": "application/json",
        "User-Agent": "Node-RED/Hacesoft-Linea"
    };

    // Příprava payloadu s informacemi o requestu
    msg.payload = {
        request_info: {
            api: "sunrise-sunset.org",
            latitude: latitude,
            longitude: longitude,
            date: todayDate,
            timezone: sTZidentifier,
            localized_date: localizedDate,
            url: fullUrl
        }
    };

} else {
    if (debug) {
        node.warn("GPS souřadnice nenalezeny");
    }
}
return msg;

// Funkce pro získání lokalizovaného data
function getLocalizedDate() {
    const currentTime = new Date();
    const sDate = currentTime.toLocaleString(sCounty_Code, { timeZone: sTZidentifier });
    return sDate;
}

// Funkce pro získání data ve formátu YYYY-MM-DD
function getTodayDateString() {
    const currentTime = new Date();
    // Převedení na lokální čas podle timezone
    const localTime = new Date(currentTime.toLocaleString("en-US", { timeZone: sTZidentifier }));

    const year = localTime.getFullYear();
    const month = String(localTime.getMonth() + 1).padStart(2, '0');
    const day = String(localTime.getDate()).padStart(2, '0');

    return `${year}-${month}-${day}`;
}

