//*****************************************************************************
// Convert Function Number Signet To Unsignet
global.set('nConvertSignetUnsignet',function nConvertSignetUnsignet(nNumber) {
    if (nNumber > 32767) nNumber -= 65536; 
    return nNumber;
});
//*****************************************************************************
// Convert Function Number Unsignet To Signet
global.set('nConvertUnsignetToSignet', function nConvertUnsignetToSignet(nNumber) {
    if (nNumber < 0) nNumber += 65536;
    return nNumber;
});
//*****************************************************************************
// Convert Function Number Signet To Unsignet for INT32
global.set('nConvertSignetUnsignetINT32', function nConvertSignetUnsignet(nNumber) {
    // Check if the number is greater than the maximum positive value for a signed 32-bit integer
    if (nNumber > 2147483647) {
        // Subtract the range of a 32-bit unsigned integer to convert it to a signed integer
        nNumber -= 4294967296; // 2^32
    }
    return nNumber;
});
//*****************************************************************************
// Funkce pro konverzi bezznaménkové hodnoty (unsigned int32) na znaménkovou hodnotu (signed int32)
global.set('nConvertUnsignetToSignetINT32', function nConvertUnsignetToSignetINT32(nNumber) {
    // Pokud je nejvyšší bit nastaven (hodnota >= 2^31)
    if (nNumber > 2147483647) {
        // Převod na záporné číslo
        return nNumber - 4294967296; // 4294967296 = 2^32
    }
    return nNumber;
});
//*****************************************************************************
// Helper function to convert Wh to kWh or MWh
global.set('AutoformatValue',function AutoformatValue(value) {
    if (value >= 1e6) {
        return `${(value / 1e6).toFixed(2)} MWh`;
    } else if (value >= 1e3) {
        return `${(value / 1e3).toFixed(2)} kWh`;
    } else {
        return `${value.toFixed(2)} Wh`;
    }
});
//*****************************************************************************
// Funkce pro reset pole: obnoví pracovní pole ze záložního pole
global.set('resetFilenamePaths', function () {
    const backupPaths = global.get("backup_filename_paths");

    // Zkontroluj, zda záložní pole existuje a není prázdné
    if (backupPaths && backupPaths.length > 0) {
        global.set("current_filename_paths", [...backupPaths]); // Obnova pracovní kopie
        //node.warn("Pracovní pole bylo resetováno.");
    } else {
        node.warn("Záložní pole je prázdné nebo neexistuje.");
    }
    return null;
});

//*****************************************************************************
// Funkce pro zpracování prvku (odebere první prvek z pracovního pole)
global.set('shiftFilenamePath', function () {
    let currentPaths = global.get("current_filename_paths");

    // Pokud je pracovní pole prázdné, vrátíme hlášku o prázdném poli
    if (!currentPaths || currentPaths.length === 0) {
        //node.warn("Pracovní pole je prázdné, provádím reset.");
        // Reset pole, protože je prázdné
        global.get('resetFilenamePaths')();
        currentPaths = global.get("current_filename_paths");
    }

    // Odebereme první prvek z pole
    const path = currentPaths.shift(); // Odebíráme první prvek

    // Uložíme aktualizované pracovní pole zpět do globální proměnné
    global.set("current_filename_paths", currentPaths);

    // Pokud bylo pole prázdné i po resetu
    if (!path) {
        node.warn("Pole je prázdné, žádný soubor k návratu.");
        return null;
    } else {
        // Vraťme odebranou cestu
        return path;
    }
});

