//*****************************************************************************
//
// File Name        : Synchronized Time Split with Offset + Reset Startup
// Title            : Časově synchronizované rozdělení tiknutí s offsetem + reset startup
// Author           : http://www.prochazka.zde.cz
// Created          : 19-06-2025, 14:30
// Revised          : 20-06-2025, 15:34
// Version          : 4.01 - FIXED O2/O3 startup bug
// Target Platform  : Node-RED
//
// This code is distributed under the GNU Public License
// Synchronizuje VŠECHNY výstupy s reálným časem + konfigurovatelný offset
// + Rychlé startup tiknutí po reset signálu
//
//*****************************************************************************

// ========== KONFIGURACE OFFSETŮ (v sekundách) ==========
const OFFSET_1MIN = 3;      // Offset pro 1min interval (3 sekundy)
const OFFSET_2MIN = 5;      // Offset pro 2min interval (5 sekund)
const OFFSET_15MIN = 10;    // Offset pro 15min interval (10 sekund)

// ========== KONFIGURACE STARTUP OFFSETŮ PO RESETU (v sekundách) ==========
const STARTUP_O2_DELAY = 15;   // O2 tikne 15 sekund po resetu
const STARTUP_O3_DELAY = 20;   // O3 tikne 20 sekund po resetu  
const STARTUP_O4_DELAY = 25;   // O4 tikne 25 sekund po resetu

// Debugging flag
const debug = false;  // ZAPNUTO PRO TESTOVÁNÍ

// ========== KONTROLA RESET SIGNÁLU ==========
const isResetSignal = (msg.payload && typeof msg.payload === 'object' && msg.payload.reset === true);

if (isResetSignal) {
    // RESET - vymazání kontextu a restart
    context.lastSent = undefined;
    context.lastSync = undefined;
    context.firstRun = undefined;
    context.startupTime = undefined;
    context.startupTicksSent = undefined;

    if (debug) {
        node.warn("=== RESET PŘIJAT ===");
    }

    node.status({ fill: "red", shape: "ring", text: "Reset přijat" });

    // Po resetu vrátit null pro všechny výstupy
    return [null, null, null, null];
}

// Získání aktuálního času - DEFINOVÁNO JEDNOU NA ZAČÁTKU
const now = new Date();
const timeStr = now.toLocaleTimeString();
const currentMinutes = now.getMinutes();
const currentSeconds = now.getSeconds();
const timestamp = now.getTime();

// Debug informace hned na začátku
if (debug) {
    node.warn("=== DEBUG START ===");
    node.warn("Čas: " + timeStr + ", Min: " + currentMinutes + ", Sec: " + currentSeconds);
    node.warn("Offset 1min: " + OFFSET_1MIN + "s, 2min: " + OFFSET_2MIN + "s, 15min: " + OFFSET_15MIN + "s");
    node.warn("Startup offsety - O2: " + STARTUP_O2_DELAY + "s, O3: " + STARTUP_O3_DELAY + "s, O4: " + STARTUP_O4_DELAY + "s");
}

// Inicializace při prvním spuštění
if (context.lastSent === undefined) {
    context.lastSent = {
        okamzity: 0,
        min1: 0,
        min2: 0,
        min15: 0
    };
    context.lastSync = {
        min1: -1,   // Poslední minuta kdy byl poslán 1min sync
        min2: -1,   // Poslední minuta kdy byl poslán 2min sync (sudé minuty)
        min15: -1   // Poslední minuta kdy byl poslán 15min sync
    };
    context.firstRun = true;
    context.startupTime = timestamp; // Čas startu pro výpočet startup tiknutí
    context.startupTicksSent = {     // Sledování odeslaných startup tiknutí
        o2: false,
        o3: false,
        o4: false
    };

    if (debug) {
        node.warn("První spuštění - inicializace v " + timeStr);
    }

    // Při prvním spuštění vrátit null pro všechny výstupy
    return [null, null, null, null];
}

let outputs = [null, null, null, null];

// Po prvním spuštění již normálně posílat zprávy
if (context.firstRun) {
    context.firstRun = false;
    context.lastSent.okamzity = timestamp;
    context.lastSent.min1 = timestamp;
    context.lastSent.min2 = timestamp;
    context.lastSent.min15 = timestamp;

    if (debug) {
        node.warn("Inicializace dokončena v " + timeStr);
    }
} else {
    // Výpočet času od startu v sekundách
    const secondsFromStart = Math.floor((timestamp - context.startupTime) / 1000);

    // ========== STARTUP TIKNUTÍ PO RESETU ==========
    // O2 startup tiknutí - OPRAVENO: outputs[1] místo outputs[2]
    if (secondsFromStart >= STARTUP_O2_DELAY && !context.startupTicksSent.o2) {
        outputs[1] = {
            payload: "Startup sync O2",
            timestamp: timestamp,
            interval: "O2 - startup sync",
            currentTime: timeStr,
            startupTick: true,
            startupDelay: STARTUP_O2_DELAY,
            secondsFromStart: secondsFromStart,
            outputName: "O2"
        };

        context.startupTicksSent.o2 = true;
        context.lastSent.min2 = timestamp;

        if (debug) {
            node.warn("O2 STARTUP: " + timeStr + " (" + secondsFromStart + "s od startu) -> outputs[1]");
        }
    }

    // O3 startup tiknutí - SPRÁVNĚ: outputs[2]
    if (secondsFromStart >= STARTUP_O3_DELAY && !context.startupTicksSent.o3) {
        outputs[2] = {
            payload: "Startup sync O3",
            timestamp: timestamp,
            interval: "O3 - startup sync",
            currentTime: timeStr,
            startupTick: true,
            startupDelay: STARTUP_O3_DELAY,
            secondsFromStart: secondsFromStart,
            outputName: "O3"
        };

        context.startupTicksSent.o3 = true;
        context.lastSent.min2 = timestamp;

        if (debug) {
            node.warn("O3 STARTUP: " + timeStr + " (" + secondsFromStart + "s od startu) -> outputs[2]");
        }
    }

    // O4 startup tiknutí - SPRÁVNĚ: outputs[3]
    if (secondsFromStart >= STARTUP_O4_DELAY && !context.startupTicksSent.o4) {
        outputs[3] = {
            payload: "Startup sync 15 minut - SPOT",
            timestamp: timestamp,
            interval: "15 minut - startup sync",
            currentTime: timeStr,
            startupTick: true,
            startupDelay: STARTUP_O4_DELAY,
            secondsFromStart: secondsFromStart,
            spotReady: true,  // Flag pro SPOT načítání
            outputName: "O4"
        };

        context.startupTicksSent.o4 = true;
        context.lastSent.min15 = timestamp;

        if (debug) {
            node.warn("O4 STARTUP: " + timeStr + " (" + secondsFromStart + "s od startu) - SPOT READY! -> outputs[3]");
        }

        // Speciální status pro startup
        node.status({
            fill: "orange",
            shape: "dot",
            text: "STARTUP O4 " + timeStr + " (+" + secondsFromStart + "s)"
        });
    }

    // ========== OKAMŽITÝ VÝSTUP - při každém tiknutí ==========
    outputs[0] = {
        payload: "Okamžitý výstup",
        timestamp: timestamp,
        interval: "okamžitý",
        currentTime: timeStr,
        outputName: "O1"
    };
    context.lastSent.okamzity = timestamp;

    // Základní stav uzlu (pokud není startup)
    if (secondsFromStart < STARTUP_O4_DELAY || context.startupTicksSent.o4) {
        node.status({ fill: "green", shape: "dot", text: "Tik: " + timeStr });
    }

    // ========== 1 MINUTOVÝ INTERVAL - synchronizovaný s offsetem ==========
    // Tikne každou minutu v OFFSET_1MIN sekundách (např. 10:15:03, 10:16:03...)
    if (currentSeconds >= OFFSET_1MIN && currentSeconds <= (OFFSET_1MIN + 10) &&
        context.lastSync.min1 !== currentMinutes) {

        // POZOR: Nepřepisovat startup zprávu!
        if (outputs[1] === null) {
            outputs[1] = {
                payload: "Sync 1 minuta",
                timestamp: timestamp,
                interval: "1 minuta - sync",
                currentTime: timeStr,
                offsetUsed: OFFSET_1MIN,
                syncMinute: currentMinutes,
                startupTick: false,
                outputName: "O2"
            };
        }

        context.lastSync.min1 = currentMinutes;
        context.lastSent.min1 = timestamp;

        if (debug) {
            node.warn("1min SYNC: " + timeStr + " (offset: " + OFFSET_1MIN + "s) -> outputs[1]");
        }
    }

    // ========== 2 MINUTOVÝ INTERVAL - synchronizovaný s offsetem ==========
    // Tikne každé 2 minuty (sudé minuty) v OFFSET_2MIN sekundách
    // POUZE pokud už proběhl startup nebo není startup aktivní
    const is2MinSync = (currentMinutes % 2 === 0);
    const startup2Complete = context.startupTicksSent.o2 && context.startupTicksSent.o3;

    if (is2MinSync && currentSeconds >= OFFSET_2MIN && currentSeconds <= (OFFSET_2MIN + 10) &&
        context.lastSync.min2 !== currentMinutes && startup2Complete) {

        // POZOR: Nepřepisovat startup zprávu!
        if (outputs[2] === null) {
            outputs[2] = {
                payload: "Sync 2 minuty",
                timestamp: timestamp,
                interval: "2 minuty - sync",
                currentTime: timeStr,
                offsetUsed: OFFSET_2MIN,
                syncMinute: currentMinutes,
                nextSync: currentMinutes + 2,
                startupTick: false,
                outputName: "O3"
            };
        }

        context.lastSync.min2 = currentMinutes;
        context.lastSent.min2 = timestamp;

        if (debug) {
            node.warn("2min SYNC: " + timeStr + " (offset: " + OFFSET_2MIN + "s) -> outputs[2]");
        }
    }

    // ========== 15 MINUTOVÝ INTERVAL - synchronizovaný s offsetem ==========
    // Tikne každých 15 minut (0, 15, 30, 45) v OFFSET_15MIN sekundách
    // POUZE pokud už proběhl startup
    const is15MinSync = (currentMinutes % 15 === 0);
    const startup15Complete = context.startupTicksSent.o4;

    if (is15MinSync && currentSeconds >= OFFSET_15MIN && currentSeconds <= (OFFSET_15MIN + 10) &&
        context.lastSync.min15 !== currentMinutes && startup15Complete) {

        const nextSyncMinute = ((Math.floor(currentMinutes / 15) + 1) * 15) % 60;

        // POZOR: Nepřepisovat startup zprávu!
        if (outputs[3] === null) {
            outputs[3] = {
                payload: "Sync 15 minut - SPOT",
                timestamp: timestamp,
                interval: "15 minut - sync",
                currentTime: timeStr,
                offsetUsed: OFFSET_15MIN,
                syncMinute: currentMinutes,
                nextSync: nextSyncMinute,
                spotReady: true,  // Flag pro SPOT načítání
                startupTick: false,
                outputName: "O4"
            };
        }

        context.lastSync.min15 = currentMinutes;
        context.lastSent.min15 = timestamp;

        if (debug) {
            node.warn("15min SYNC: " + timeStr + " (offset: " + OFFSET_15MIN + "s) - SPOT READY! -> outputs[3]");
        }

        // Speciální status pro 15min sync
        node.status({
            fill: "blue",
            shape: "dot",
            text: "SPOT SYNC " + timeStr + " (+" + OFFSET_15MIN + "s)"
        });
    }
}

// Závěrečný debug
if (debug) {
    const sync1 = (currentSeconds >= OFFSET_1MIN && currentSeconds <= (OFFSET_1MIN + 10));
    const sync2 = ((currentMinutes % 2 === 0) && currentSeconds >= OFFSET_2MIN && currentSeconds <= (OFFSET_2MIN + 10));
    const sync15 = ((currentMinutes % 15 === 0) && currentSeconds >= OFFSET_15MIN && currentSeconds <= (OFFSET_15MIN + 10));
    const secondsFromStart = Math.floor((timestamp - context.startupTime) / 1000);

    node.warn("Sync okna - 1min: " + sync1 + ", 2min: " + sync2 + ", 15min: " + sync15);
    node.warn("Startup: " + secondsFromStart + "s, O2:" + context.startupTicksSent.o2 +
        ", O3:" + context.startupTicksSent.o3 + ", O4:" + context.startupTicksSent.o4);
    node.warn("Outputs: [" + (outputs[0] ? "O1" : "null") + ", " +
        (outputs[1] ? "O2" : "null") + ", " +
        (outputs[2] ? "O3" : "null") + ", " +
        (outputs[3] ? "O4" : "null") + "]");
    node.warn("=== DEBUG END ===");
}

return outputs;

