//
//*****************************************************************************
// Pouze zobrazuje informace ze zprávy - ŽÁDNÁ časová logika!
const debug = false;

if (msg.payload) {
    const timeStr = msg.currentTime || new Date().toLocaleTimeString();

    let statusText = "";
    let fillColor = "orange";
    let shape = "ring";

    // Rozlišení typu zprávy podle msg.interval (přichází z hlavní funkce)
    if (msg.startupTick) {
        // Startup tiknutí
        statusText = `STARTUP ${timeStr} (+${msg.secondsFromStart}s)`;
        fillColor = "yellow";
        shape = "dot";

        if (debug) {
            node.warn(`O2: STARTUP tiknutí po ${msg.secondsFromStart} sekundách`);
        }
    } else if (msg.interval && msg.interval.includes("sync")) {
        // Synchronizované tiknutí
        statusText = `SYNC ${timeStr}`;
        fillColor = "green";
        shape = "dot";

        // Zobrazit další sync pokud je k dispozici
        if (msg.nextSyncIn) {
            statusText += ` (další za ${msg.nextSyncIn}min)`;
        }

        if (debug) {
            node.warn(`O2: Sync tiknutí v ${timeStr}`);
        }
    } else {
        // Ostatní zprávy
        statusText = `${timeStr} - ${msg.interval || 'neznámý'}`;
    }

    node.status({
        fill: fillColor, 
        shape: shape, 
        text: statusText
    });

    // Přidat jen monitoring informace
    msg.monitoredBy = "O2";
    msg.monitoredAt = new Date().toISOString();

    return msg;
} else {
    node.status({});
    return null;
}

